import{_ as e,c as l,o as a,a as n}from"./app.2be4be53.js";const f=JSON.parse(`{"title":"\u4E3A\u4EC0\u4E48 typeof null === 'object'","description":"","frontmatter":{},"headers":[{"level":2,"title":"1 \u95EE\u9898\u63CF\u8FF0","slug":"_1-\u95EE\u9898\u63CF\u8FF0","link":"#_1-\u95EE\u9898\u63CF\u8FF0","children":[]},{"level":2,"title":"2 \u7B80\u8981\u89E3\u91CA","slug":"_2-\u7B80\u8981\u89E3\u91CA","link":"#_2-\u7B80\u8981\u89E3\u91CA","children":[]},{"level":2,"title":"3 \u8BE6\u7EC6\u89E3\u91CA","slug":"_3-\u8BE6\u7EC6\u89E3\u91CA","link":"#_3-\u8BE6\u7EC6\u89E3\u91CA","children":[{"level":3,"title":"3.1 \u4E3A\u4F55\u53E4\u8001\u7684\u4EE3\u7801\u4E2D typeof null === 'object'","slug":"_3-1-\u4E3A\u4F55\u53E4\u8001\u7684\u4EE3\u7801\u4E2D-typeof-null-object","link":"#_3-1-\u4E3A\u4F55\u53E4\u8001\u7684\u4EE3\u7801\u4E2D-typeof-null-object","children":[]},{"level":3,"title":"3.2 \u4E3A\u4F55\u73B0\u4EE3 V8 \u5F15\u64CE\u4EE3\u7801\u4E2D typeof null === 'object'","slug":"_3-2-\u4E3A\u4F55\u73B0\u4EE3-v8-\u5F15\u64CE\u4EE3\u7801\u4E2D-typeof-null-object","link":"#_3-2-\u4E3A\u4F55\u73B0\u4EE3-v8-\u5F15\u64CE\u4EE3\u7801\u4E2D-typeof-null-object","children":[]}]},{"level":2,"title":"4 \u89E3\u51B3\u529E\u6CD5","slug":"_4-\u89E3\u51B3\u529E\u6CD5","link":"#_4-\u89E3\u51B3\u529E\u6CD5","children":[]},{"level":2,"title":"5 \u53C2\u8003","slug":"_5-\u53C2\u8003","link":"#_5-\u53C2\u8003","children":[]}],"relativePath":"blog/basic-javascript-knowledge/fragment/why-typeof-null-and-object-are-all-equal.md","lastUpdated":1670679481000}`),s={name:"blog/basic-javascript-knowledge/fragment/why-typeof-null-and-object-are-all-equal.md"},o=n(`<h1 id="\u4E3A\u4EC0\u4E48-typeof-null-object" tabindex="-1">\u4E3A\u4EC0\u4E48 typeof null === &#39;object&#39; <a class="header-anchor" href="#\u4E3A\u4EC0\u4E48-typeof-null-object" aria-hidden="true">#</a></h1><h2 id="_1-\u95EE\u9898\u63CF\u8FF0" tabindex="-1">1 \u95EE\u9898\u63CF\u8FF0 <a class="header-anchor" href="#_1-\u95EE\u9898\u63CF\u8FF0" aria-hidden="true">#</a></h2><p>\u524D\u7AEF\u7A0B\u5E8F\u5458\u90FD\u77E5\u9053\uFF0C<code>typeof null</code> \u662F\u4E00\u4E2A\u5751\uFF0C\u4F1A\u51FA\u73B0\u4E0D\u7B26\u5408\u9884\u671F\u7684\u7ED3\u679C\u3002 <code>typeof null === &#39;object&#39;</code>\u3002</p><p>\u66F4\u672C\u8D28\u7684\u539F\u56E0\u662F\u4EC0\u4E48\u5462\uFF1F</p><h2 id="_2-\u7B80\u8981\u89E3\u91CA" tabindex="-1">2 \u7B80\u8981\u89E3\u91CA <a class="header-anchor" href="#_2-\u7B80\u8981\u89E3\u91CA" aria-hidden="true">#</a></h2><p><code>typeof null === &#39;object&#39;</code> \u662F JavaScript \u4E2D\u7B2C\u4E00\u4E2A\u7248\u672C\u4E2D\u5C31\u6709\u7684 bug\u3002\u540E\u6765\u6709\u4EBA\u60F3\u4FEE\u590D\u8FD9\u4E2A bug\uFF0C\u4F46\u63D0\u6848\u6CA1\u6709\u88AB\u63A5\u53D7\u3002</p><p>\u4E45\u800C\u4E45\u4E4B\uFF0C\u8FD9\u4E2A bug \u5C31\u6210\u4E3A\u5927\u5BB6\u516C\u8BA4\u7684 feature \u4E86\uFF0C\u540E\u7EED V8 \u5F15\u64CE\u5355\u72EC\u5904\u7406\u4E86 <code>typeof null</code> \u7684\u60C5\u51B5\u3002</p><h2 id="_3-\u8BE6\u7EC6\u89E3\u91CA" tabindex="-1">3 \u8BE6\u7EC6\u89E3\u91CA <a class="header-anchor" href="#_3-\u8BE6\u7EC6\u89E3\u91CA" aria-hidden="true">#</a></h2><h3 id="_3-1-\u4E3A\u4F55\u53E4\u8001\u7684\u4EE3\u7801\u4E2D-typeof-null-object" tabindex="-1">3.1 \u4E3A\u4F55\u53E4\u8001\u7684\u4EE3\u7801\u4E2D typeof null === &#39;object&#39; <a class="header-anchor" href="#_3-1-\u4E3A\u4F55\u53E4\u8001\u7684\u4EE3\u7801\u4E2D-typeof-null-object" aria-hidden="true">#</a></h3><p>\u76EE\u524D\u6709\u5173\u8FD9\u4E00 bug\uFF0CAxel Rauschmayer \u627E\u5230\u4E86 1996 \u5E74\u7684\u8001\u4EE3\u7801\uFF08JavaScript \u662F 1995 \u5E74\u53D1\u5E03\u7684\uFF09\u3002</p><p>\u5728\u8FD9\u4E00\u7248\u7684\u4EE3\u7801\u4E2D\uFF0CJavaScript \u901A\u8FC7 32 bit \u6765\u5B58\u50A8\u503C\u3002\u5B9A\u4E49\u4E86 5 \u79CD\u7C7B\u578B\u548C 2 \u4E2A\u7279\u6B8A\u503C\u3002</p><p>5 \u79CD\u7C7B\u578B\u662F\u901A\u8FC7 32 \u4F4D\u4E2D\u4F4E 1 \u4F4D\u6216\u8005\u4F4E 3 \u4F4D\u6765\u8BC6\u522B\u7C7B\u578B\u7684\u3002</p><ul><li>0 ---&gt; object</li><li>1 ---&gt; int</li><li>010 ---&gt; double</li><li>100 ---&gt; string</li><li>110 ---&gt; boolean</li></ul><p>2 \u4E2A\u7279\u6B8A\u503C\u5982\u4E0B\uFF1A</p><ul><li>undefiend\uFF0C\u7528\u6574\u6570 <code>-2^30</code> \u6765\u8868\u793A\uFF08\u8FD9\u4E2A\u6570\u5DF2\u7ECF\u4E0D\u5728\u6574\u6570\u8303\u56F4\u4E86\uFF09</li><li>null\uFF0CC/C++ \u7684 NULL\uFF0C\u4F4E 3 \u4F4D\u4E5F\u662F 000</li></ul><p>\u56E0\u6B64\u5BFC\u81F4\u4E86 <code>typeof null === &#39;object&#39;</code>\u3002</p><p>\u4F46\u6309\u7167 Brendan Eich\uFF08JavaScript \u8BBE\u8BA1\u8005\uFF09\u7684\u8BF4\u6CD5\uFF0C\u4ED6\u4E4B\u6240\u4EE5\u8FD9\u6837\u5199\uFF0C\u4E5F\u662F\u4E3A\u4E86\u586B 1995 \u5E74\u7684\u5751\u3002</p><blockquote><p>Hi Axel -- small correction: the code you show is from SpiderMonkey, which I wrote in 1996 to pay off tech debt in Mocha, the first JS implementation from the 10 days in May 1995. Mocha used a discriminated union in C (struct with type tag and union whose arms corresponded to the enumerated tag values). Same bug, though. Just a historical detail. Regards,</p></blockquote><p>\u7FFB\u8BD1\uFF1A</p><blockquote><p>Hi Axel \u5C0F\u66F4\u6B63\uFF1A\u4F60\u5C55\u793A\u7684\u4EE3\u7801\u6765\u81EA SpiderMonkey\uFF0C\u662F\u6211\u5728 1996 \u5E74\u5199\u7684\uFF0C\u76EE\u7684\u662F\u507F\u8FD8 Mocha \u7684\u6280\u672F\u503A\u52A1\u30021995 \u5E74 5 \u6708 10 \u65E5\uFF0C\u7B2C\u4E00\u6B21 JavaScript \u5B9E\u73B0\uFF0CMocha \u5728 C \u8BED\u8A00\u4E2D\u4F7F\u7528\u4E86\u4E00\u4E2A discriminated union\uFF08discriminated union \u662F\u5177\u6709\u7C7B\u578B\u6807\u8BB0\u548C union \u7684\u7ED3\u6784\uFF0C\u5B83\u7684 arms \u548C\u679A\u4E3E\u7684\u6807\u8BB0\u503C\u76F8\u5BF9\u5E94\uFF09\u3002\u5F53\u7136 Bug \u548C\u8FD9\u91CC\u7684\u662F\u4E00\u6837\u7684\uFF0C\u6211\u53EA\u662F\u8BB2\u4E00\u4E0B\u5386\u53F2\u7684\u7EC6\u8282\u3002 \u2014\u2014 <a href="https://2ality.com/2013/10/typeof-null.html" target="_blank" rel="noreferrer">The history of &quot;typeof null&quot;</a></p></blockquote><h3 id="_3-2-\u4E3A\u4F55\u73B0\u4EE3-v8-\u5F15\u64CE\u4EE3\u7801\u4E2D-typeof-null-object" tabindex="-1">3.2 \u4E3A\u4F55\u73B0\u4EE3 V8 \u5F15\u64CE\u4EE3\u7801\u4E2D typeof null === &#39;object&#39; <a class="header-anchor" href="#_3-2-\u4E3A\u4F55\u73B0\u4EE3-v8-\u5F15\u64CE\u4EE3\u7801\u4E2D-typeof-null-object" aria-hidden="true">#</a></h3><blockquote><p>\u4ECE V8 \u6E90\u7801\u6765\u770B\uFF0C<code>typeof null</code> \u662F\u5F53\u505A\u4E00\u4E2A\u7279\u6B8A\u60C5\u51B5\u5904\u7406\u7684\uFF0C\u662F\u4E2A\u9700\u8981\u517C\u5BB9\u7684\u5386\u53F2\u5305\u88B1\u3002</p></blockquote><div class="language-c"><button title="Copy Code" class="copy"></button><span class="lang">c</span><pre><code><span class="line"><span style="color:#676E95;">// \u5982\u679C instance_type \u662F ODDBALL_TYPE\uFF08\u503C\u4E3A 67\uFF09</span></span>
<span class="line"><span style="color:#676E95;">// \u8DF3\u8F6C\u5230 if_oddball \u6267\u884C</span></span>
<span class="line"><span style="color:#82AAFF;">GotoIf</span><span style="color:#89DDFF;">(</span></span>
<span class="line"><span style="color:#A6ACCD;">  </span><span style="color:#82AAFF;">InstanceTypeEqual</span><span style="color:#89DDFF;">(</span><span style="color:#A6ACCD;">instance_type</span><span style="color:#89DDFF;">,</span><span style="color:#A6ACCD;"> ODDBALL_TYPE</span><span style="color:#89DDFF;">),</span></span>
<span class="line"><span style="color:#A6ACCD;">  </span><span style="color:#89DDFF;">&amp;</span><span style="color:#A6ACCD;">if_oddball</span></span>
<span class="line"><span style="color:#89DDFF;">)</span></span>
<span class="line"></span></code></pre></div><blockquote><p>ODDBALL_TYPE \u5982\u679C\u7FFB\u8BD1\u6210\u4E2D\u6587\u7684\u8BDD\uFF0C\u53EF\u80FD\u4F1A\u53EB\u5947\u602A\u7C7B\u578B\uFF0C\u81F3\u5C11\u4ECE ODDBALL_TYPE \u7684\u547D\u540D\u6765\u770B\uFF0CV8 \u4E5F\u8BA4\u4E3A null \u662F\u4E00\u4E2A\u4E0D\u8D70\u5BFB\u5E38\u8DEF\u7684\u7C7B\u578B\u3002 \u2014\u2014 <a href="https://zhuanlan.zhihu.com/p/143590829" target="_blank" rel="noreferrer">typeof \u4E0E Javascript \u7C7B\u578B\u6E90\u7801\u5206\u6790 - \u77E5\u4E4E (zhihu.com)</a></p></blockquote><h2 id="_4-\u89E3\u51B3\u529E\u6CD5" tabindex="-1">4 \u89E3\u51B3\u529E\u6CD5 <a class="header-anchor" href="#_4-\u89E3\u51B3\u529E\u6CD5" aria-hidden="true">#</a></h2><p>\u5982\u679C\u6211\u4EEC\u9700\u8981\u5224\u65AD\u53D8\u91CF val \u662F\u5426\u4E3A null \u8BDD\uFF0C\u53EF\u4EE5\u91C7\u7528\u4E24\u79CD\u529E\u6CD5\u3002\u63A8\u8350\u91C7\u7528\u7B2C\u4E00\u79CD\u529E\u6CD5\u3002</p><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre><code><span class="line"><span style="color:#676E95;">// \u7B2C\u4E00\u79CD\u529E\u6CD5</span></span>
<span class="line"><span style="color:#89DDFF;">if</span><span style="color:#A6ACCD;"> (val </span><span style="color:#89DDFF;">===</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">null</span><span style="color:#A6ACCD;">) </span><span style="color:#89DDFF;">{</span></span>
<span class="line"><span style="color:#89DDFF;">  </span><span style="color:#676E95;">// ...</span></span>
<span class="line"><span style="color:#89DDFF;">}</span></span>
<span class="line"></span>
<span class="line"><span style="color:#676E95;">// \u7B2C\u4E8C\u79CD\u529E\u6CD5</span></span>
<span class="line"><span style="color:#89DDFF;">if</span><span style="color:#A6ACCD;"> (</span><span style="color:#FFCB6B;">Object</span><span style="color:#89DDFF;">.</span><span style="color:#A6ACCD;">prototype</span><span style="color:#89DDFF;">.</span><span style="color:#A6ACCD;">toString</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">call</span><span style="color:#A6ACCD;">(val) </span><span style="color:#89DDFF;">===</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">&#39;</span><span style="color:#C3E88D;">[object Null]</span><span style="color:#89DDFF;">&#39;</span><span style="color:#A6ACCD;">) </span><span style="color:#89DDFF;">{</span></span>
<span class="line"><span style="color:#89DDFF;">  </span><span style="color:#676E95;">// ...</span></span>
<span class="line"><span style="color:#89DDFF;">}</span></span>
<span class="line"></span></code></pre></div><h2 id="_5-\u53C2\u8003" tabindex="-1">5 \u53C2\u8003 <a class="header-anchor" href="#_5-\u53C2\u8003" aria-hidden="true">#</a></h2><ul><li><a href="https://2ality.com/2013/10/typeof-null.html" target="_blank" rel="noreferrer">The history of &quot;typeof null&quot;</a></li><li><a href="https://zhuanlan.zhihu.com/p/143590829" target="_blank" rel="noreferrer">typeof \u4E0E Javascript \u7C7B\u578B\u6E90\u7801\u5206\u6790 - \u77E5\u4E4E (zhihu.com)</a></li></ul>`,29),t=[o];function p(c,r,i,d,u,h){return a(),l("div",null,t)}const D=e(s,[["render",p]]);export{f as __pageData,D as default};
